   483 | // Decomposes \p V into a constant offset + list of pairs { Coefficient,
   484 | // Variable } where Coefficient * Variable. The sum of the constant offset and
   485 | // pairs equals \p V.
   486 | static Decomposition decompose(Value *V,
   487 |                                SmallVectorImpl<ConditionTy> &Preconditions,
   488 |                                bool IsSigned, const DataLayout &DL) {
   489 | 
   490 |   auto MergeResults = [&Preconditions, IsSigned, &DL](Value *A, Value *B,
   491 |                                                       bool IsSignedB) {
   492 |     auto ResA = decompose(A, Preconditions, IsSigned, DL);
   493 |     auto ResB = decompose(B, Preconditions, IsSignedB, DL);
   494 |     ResA.add(ResB);
   495 |     return ResA;
   496 |   };
   497 | 
   498 |   Type *Ty = V->getType()->getScalarType();
   499 |   if (Ty->isPointerTy() && !IsSigned) {
   500 |     if (auto *GEP = dyn_cast<GEPOperator>(V))
   501 |       return decomposeGEP(*GEP, Preconditions, IsSigned, DL);
   502 |     if (isa<ConstantPointerNull>(V))
   503 |       return int64_t(0);
   504 | 
   505 |     return V;
   506 |   }
   507 | 
   508 |   // Don't handle integers > 64 bit. Our coefficients are 64-bit large, so
   509 |   // coefficient add/mul may wrap, while the operation in the full bit width
   510 |   // would not.
   511 |   if (!Ty->isIntegerTy() || Ty->getIntegerBitWidth() > 64)
   512 |     return V;
   513 | 
   514 |   bool IsKnownNonNegative = false;
   515 | 
   516 |   // Decompose \p V used with a signed predicate.
   517 |   if (IsSigned) {
   518 |     if (auto *CI = dyn_cast<ConstantInt>(V)) {
   519 |       if (canUseSExt(CI))
   520 |         return CI->getSExtValue();
   521 |     }
   522 |     Value *Op0;
   523 |     Value *Op1;
   524 | 
   525 |     if (match(V, m_SExt(m_Value(Op0))))
   526 |       V = Op0;
   527 |     else if (match(V, m_NNegZExt(m_Value(Op0)))) {
   528 |       V = Op0;
   529 |       IsKnownNonNegative = true;
   530 |     } else if (match(V, m_NSWTrunc(m_Value(Op0)))) {
   531 |       if (Op0->getType()->getScalarSizeInBits() <= 64)
   532 |         V = Op0;
   533 |     }
   534 | 
   535 |     if (match(V, m_NSWAdd(m_Value(Op0), m_Value(Op1))))
   536 |       return MergeResults(Op0, Op1, IsSigned);
   537 | 
   538 |     if (match(V, m_NSWSub(m_Value(Op0), m_Value(Op1)))) {
   539 |       auto ResA = decompose(Op0, Preconditions, IsSigned, DL);
   540 |       auto ResB = decompose(Op1, Preconditions, IsSigned, DL);
   541 |       ResA.sub(ResB);
   542 |       return ResA;
   543 |     }
   544 | 
   545 |     ConstantInt *CI;
   546 |     if (match(V, m_NSWMul(m_Value(Op0), m_ConstantInt(CI))) && canUseSExt(CI)) {
   547 |       auto Result = decompose(Op0, Preconditions, IsSigned, DL);
   548 |       Result.mul(CI->getSExtValue());
   549 |       return Result;
   550 |     }
   551 | 
   552 |     // (shl nsw x, shift) is (mul nsw x, (1<<shift)), with the exception of
   553 |     // shift == bw-1.
   554 |     if (match(V, m_NSWShl(m_Value(Op0), m_ConstantInt(CI)))) {
   555 |       uint64_t Shift = CI->getValue().getLimitedValue();
   556 |       if (Shift < Ty->getIntegerBitWidth() - 1) {
   557 |         assert(Shift < 64 && "Would overflow");
   558 |         auto Result = decompose(Op0, Preconditions, IsSigned, DL);
   559 |         Result.mul(int64_t(1) << Shift);
   560 |         return Result;
   561 |       }
   562 |     }
   563 | 
   564 |     return {V, IsKnownNonNegative};
   565 |   }
   566 | 
   567 |   if (auto *CI = dyn_cast<ConstantInt>(V)) {
   568 |     if (CI->uge(MaxConstraintValue))
