   570 |     return int64_t(CI->getZExtValue());
   571 |   }
   572 | 
   573 |   Value *Op0;
   574 |   if (match(V, m_ZExt(m_Value(Op0)))) {
   575 |     IsKnownNonNegative = true;
   576 |     V = Op0;
   577 |   } else if (match(V, m_SExt(m_Value(Op0)))) {
   578 |     V = Op0;
