   632 |     return Result;
   633 |   }
   634 | 
   635 |   if (match(V, m_NUWSub(m_Value(Op0), m_Value(Op1)))) {
   636 |     auto ResA = decompose(Op0, Preconditions, IsSigned, DL);
   637 |     auto ResB = decompose(Op1, Preconditions, IsSigned, DL);
   638 |     ResA.sub(ResB);
   639 |     return ResA;
   640 |   }
