  // (X | Y) != 0 is equivalent to X != 0 || Y != 0.
  // If we know X != Y, then (X | Y) != 0 is true and (X | Y) == 0 is false.
  Value *OrOp0, *OrOp1;
  if (match(Op0, m_Or(m_Value(OrOp0), m_Value(OrOp1))) &&
