    // For (X | Y) != 0 (IsNe case), add preconditions X != 0 or Y != 0.
    // We handle this by converting to a form the constraint system can reason
    // about: (X | Y) == 0 becomes X == 0 && Y == 0.
    if (!IsEq && !IsNe) {
